/**
 * Search locations by partial display name (case-insensitive)
 */
function searchLocations(query) {
    const q = query.toLowerCase().trim();
    if (!q) return US_LOCATIONS.slice(0, 25);
    return US_LOCATIONS.filter(loc =>
        loc.display.toLowerCase().includes(q) ||
        loc.value.toLowerCase().includes(q)
    ).slice(0, 25);
}

/**
 * Get all locations
 */
function getAllLocations() {
    return US_LOCATIONS;
}

/**
 * Get location with coordinates by name or display
 */
function getLocationWithCoordinates(location) {
    if (!location) return null;
    
    // Normalize input: convert to lowercase, remove all spaces after commas for consistent comparison
    const inputLower = location.toLowerCase();
    const inputNormalized = inputLower.replace(/,\s*/g, ',').trim();
    
    // Find by trying multiple match strategies
    // Strategy 1: Exact match after normalizing both value and input (ignoring spaces)
    let match = US_LOCATIONS.find(l => {
        const dbNormalized = l.value.toLowerCase().replace(/,\s*/g, ',').trim();
        return dbNormalized === inputNormalized;
    });
    if (match) return match;
    
    // Strategy 2: Try with spaces added back (in case database format matters)
    const inputWithSpaces = inputNormalized.replace(/,/g, ', ').trim();
    match = US_LOCATIONS.find(l => 
        l.value.toLowerCase() === inputWithSpaces
    );
    if (match) return match;
    
    // Strategy 3: Match against display field
    match = US_LOCATIONS.find(l => {
        const displayNormalized = l.display.toLowerCase().replace(/,\s*/g, ',').trim();
        return displayNormalized === inputNormalized || 
               l.display.toLowerCase() === inputWithSpaces;
    });
    if (match) return match;
    
    // Strategy 4: Partial/fuzzy match (last resort)
    match = US_LOCATIONS.find(l => {
        const dbNormalized = l.value.toLowerCase().replace(/,\s*/g, ',').trim();
        const displayNormalized = l.display.toLowerCase().replace(/,\s*/g, ',').trim();
        return inputNormalized.includes(dbNormalized) || 
               dbNormalized.includes(inputNormalized) ||
               inputNormalized.includes(displayNormalized) ||
               displayNormalized.includes(inputNormalized);
    });
    
    return match || null;
}

/**
 * Legacy: get a location code — now we use value strings directly
 * Returns null to signal "use the string directly"
 */
function getLocationCode(name) {
    return null;
}

module.exports = { US_LOCATIONS, searchLocations, getAllLocations, getLocationWithCoordinates, getLocationCode };
